// ============================================================
// HBStage<N_ODD>: one channel of one halfband ×2 upsampling stage.
//
// Delay buffer: buf[0] = newest input, buf[2*N_ODD-1] = oldest input.
// After pushing input x[k]:
//   even_out = 0.5 * buf[N_ODD]          = 0.5 * x[k - N_ODD]
//   odd_out  = Σ h[j] * (buf[N_ODD-1-j] + buf[N_ODD+j])
// Both outputs share the same group delay of N_ODD input samples.
// ============================================================
template<int N_ODD>
struct HBStage {
    static constexpr int D = 2 * N_ODD;
    float buf[D] = {};

    void process(float in, const float* h, float& ev, float& od) {
        memmove(buf + 1, buf, (D - 1) * sizeof(float));
        buf[0] = in;

        // Correct unity-gain 2x interpolation:
        // even branch should pass the delayed sample at full scale,
        // odd branch needs x2 because these coeffs represent the nonzero halfband taps.
        ev = buf[N_ODD];

        float s = 0.0f;
        for (int j = 0; j < N_ODD; ++j)
            s += h[j] * (buf[N_ODD - 1 - j] + buf[N_ODD + j]);

        od = 2.0f * s;
    }    

    void reset() { memset(buf, 0, sizeof(buf)); }
};

// ============================================================
// HalfbandInterpolator: stereo 44100 Hz → 5644800 Hz (×128)
//
// Call process() once per 44100 Hz stereo PCM sample.
// Fills outL[128] and outR[128] with the 128 DSD-rate samples.
//
// Latency: ~2.2 ms (dominated by Stage 1's 84-sample delay at 44100 Hz).
// Memory:  ~18 KB for all stage delay lines (both channels).
// ============================================================
struct HalfbandInterpolator {
    // One stateful halfband stage per channel.
    // Each stage processes the full stream produced by the previous stage.

    HBStage<STAGE1_ODD_N> s1L, s1R;
    HBStage<STAGE2_ODD_N> s2L, s2R;
    HBStage<STAGE3_ODD_N> s3L, s3R;
    HBStage<STAGE4_ODD_N> s4L, s4R;
    HBStage<STAGE4_ODD_N> s5L, s5R;
    HBStage<STAGE4_ODD_N> s6L, s6R;
    HBStage<STAGE7_ODD_N> s7L, s7R;


    void reset() {
        s1L.reset(); s1R.reset();
        s2L.reset(); s2R.reset();
        s3L.reset(); s3R.reset();
        s4L.reset(); s4R.reset();
        s5L.reset(); s5R.reset();
        s6L.reset(); s6R.reset();
        s7L.reset(); s7R.reset();
    }

    // Process one 44100 Hz stereo sample; fills out[128] at 5644800 Hz.

        void process(float inL, float inR, float outL[128], float outR[128]) {
        float b1L[2],   b1R[2];
        float b2L[4],   b2R[4];
        float b3L[8],   b3R[8];
        float b4L[16],  b4R[16];
        float b5L[32],  b5R[32];
        float b6L[64],  b6R[64];

        // Stage 1: 1 input -> 2 outputs
        s1L.process(inL, STAGE1_ODD, b1L[0], b1L[1]);
        s1R.process(inR, STAGE1_ODD, b1R[0], b1R[1]);

        // Stage 2: process the full stage-1 stream through ONE stateful filter
        for (int i = 0; i < 2; ++i) {
            s2L.process(b1L[i], STAGE2_ODD, b2L[2*i], b2L[2*i+1]);
            s2R.process(b1R[i], STAGE2_ODD, b2R[2*i], b2R[2*i+1]);
        }

        // Stage 3
        for (int i = 0; i < 4; ++i) {
            s3L.process(b2L[i], STAGE3_ODD, b3L[2*i], b3L[2*i+1]);
            s3R.process(b2R[i], STAGE3_ODD, b3R[2*i], b3R[2*i+1]);
        }

        // Stage 4
        for (int i = 0; i < 8; ++i) {
            s4L.process(b3L[i], STAGE46_ODD, b4L[2*i], b4L[2*i+1]);
            s4R.process(b3R[i], STAGE46_ODD, b4R[2*i], b4R[2*i+1]);
        }

        // Stage 5
        for (int i = 0; i < 16; ++i) {
            s5L.process(b4L[i], STAGE46_ODD, b5L[2*i], b5L[2*i+1]);
            s5R.process(b4R[i], STAGE46_ODD, b5R[2*i], b5R[2*i+1]);
        }

        // Stage 6
        for (int i = 0; i < 32; ++i) {
            s6L.process(b5L[i], STAGE46_ODD, b6L[2*i], b6L[2*i+1]);
            s6R.process(b5R[i], STAGE46_ODD, b6R[2*i], b6R[2*i+1]);
        }

        // Stage 7
        for (int i = 0; i < 64; ++i) {
            s7L.process(b6L[i], STAGE7_ODD, outL[2*i], outL[2*i+1]);
            s7R.process(b6R[i], STAGE7_ODD, outR[2*i], outR[2*i+1]);
        }
    }   
};
